SELECT
  id, session_id, user_id, question_id, selected_option_keys,
  is_correct, answered_at, create_time, update_time
FROM user_answer
WHERE session_id = #{sessionId}
  AND question_id = #{questionId}
  AND user_id = #{userId}

SELECT
  id, session_id, user_id, question_id, selected_option_keys,
  is_correct, answered_at, create_time, update_time
FROM user_answer
WHERE user_id = #{userId}
  AND question_id = #{questionId}
ORDER BY answered_at DESC, id DESC
LIMIT #{limit}
